import { assertEquals } from 'jsr:@std/assert';
import { filterVendors, moveVendor, vendorPayload, type VendorRecord } from './vendorCatalogModel.ts';
const vendor = (id: string, display_order: number, category = 'Foto'): VendorRecord => ({ id, display_order, category, name: `Fornecedor ${id}`, assessor_id: 'u', phone: null, whatsapp: null, email: null, cover_image_url: null, cover_image_file_id: null, presentation_url: null, presentation_file_id: null, is_visible_in_vitrine: false, created_at: '', city: null, state: null, price_range: null });
Deno.test('vendor filters and reorder preserve stable contracts', () => { const rows = [vendor('b', 1), vendor('a', 0), vendor('c', 2, 'Buffet/Gastronomia')]; assertEquals(filterVendors(rows, 'fornecedor', 'Foto').map(({ id }) => id), ['a', 'b']); assertEquals(moveVendor(rows, 'b', 'up').map(({ id, display_order }) => [id, display_order]), [['b', 0], ['a', 1], ['c', 2]]); });
Deno.test('vendor payload trims optional contact fields', () => { assertEquals(vendorPayload({ name: ' Foto ', category: 'Foto', phone: '', whatsapp: '', email: '', is_visible_in_vitrine: false, city: '', state: '', price_range: '' }), { id: null, name: 'Foto', category: 'Foto', phone: null, whatsapp: null, email: null, is_visible_in_vitrine: false, city: null, state: null, price_range: null }); });
